1	<!doctype html>
2	<html>
3	<head>
4	    <title>Stroop Task — jsPsych 7 + ClickSense</title>
5	    <script src="https://unpkg.com/jspsych@7.3.4"></script>
6	    <script src="https://unpkg.com/@jspsych/plugin-html-keyboard-response@1.1.3"></script>
7	    <script src="https://unpkg.com/@jspsych/plugin-html-button-response@1.1.3"></script>
8	    <script src="static/js/clicksense.js"></script>
9	    <link href="https://unpkg.com/jspsych@7.3.4/css/jspsych.css" rel="stylesheet">
10	    <style>
11	        .fixation { font-size: 50px; }
12	        .stroop-word { font-size: 50px; font-weight: bold; }
13	
14	        /* Color the response buttons to match their meaning */
15	        .jspsych-btn[data-choice="0"] { /* Red */
16	            background: #d32f2f; color: white; font-weight: bold;
17	            font-size: 18px; padding: 12px 32px; border: none; border-radius: 6px;
18	            min-width: 80px; cursor: pointer;
19	        }
20	        .jspsych-btn[data-choice="1"] { /* Green */
21	            background: #388e3c; color: white; font-weight: bold;
22	            font-size: 18px; padding: 12px 32px; border: none; border-radius: 6px;
23	            min-width: 80px; cursor: pointer;
24	        }
25	        .jspsych-btn[data-choice="2"] { /* Blue */
26	            background: #1565c0; color: white; font-weight: bold;
27	            font-size: 18px; padding: 12px 32px; border: none; border-radius: 6px;
28	            min-width: 80px; cursor: pointer;
29	        }
30	
31	        #jspsych-html-button-response-btngroup {
32	            margin-top: 30px;
33	            gap: 16px;
34	        }
35	    </style>
36	</head>
37	<body></body>
38	<script>
39	
40	// --- ClickSense setup ---
41	var clicksenseData = [];
42	var cs = new ClickSenseLib.ClickSense({
43	    enableApproachDynamics: true,
44	    onCapture: function(event) {
45	        clicksenseData.push(event);
46	        console.log('ClickSense:', event.duration_ms + 'ms', event);
47	    }
48	});
49	
50	// --- jsPsych ---
51	var jsPsych = initJsPsych({
52	    on_finish: function() {
53	        var congruent = jsPsych.data.get().filter({stimulus_type: 'congruent'});
54	        var incongruent = jsPsych.data.get().filter({stimulus_type: 'incongruent'});
55	        var unrelated = jsPsych.data.get().filter({stimulus_type: 'unrelated'});
56	
57	        var html = '<div style="max-width:700px; margin:60px auto; font-family:sans-serif; line-height:1.6">';
58	        html += '<h2>Results</h2>';
59	
60	        // RT + accuracy table
61	        html += '<table style="border-collapse:collapse; width:100%; text-align:center">';
62	        html += '<tr><th style="border-bottom:2px solid #333; padding:8px">Condition</th>' +
63	                '<th style="border-bottom:2px solid #333; padding:8px">Mean RT (ms)</th>' +
64	                '<th style="border-bottom:2px solid #333; padding:8px">Accuracy</th></tr>';
65	
66	        [[congruent, 'Congruent'], [incongruent, 'Incongruent'], [unrelated, 'Unrelated']].forEach(function(pair) {
67	            var d = pair[0], label = pair[1];
68	            var rt = Math.round(d.select('rt').mean());
69	            var acc = Math.round(100 * d.select('correct').mean());
70	            html += '<tr><td style="padding:8px; border-bottom:1px solid #ddd">' + label + '</td>' +
71	                    '<td style="padding:8px; border-bottom:1px solid #ddd">' + rt + '</td>' +
72	                    '<td style="padding:8px; border-bottom:1px solid #ddd">' + acc + '%</td></tr>';
73	        });
74	        html += '</table>';
75	
76	        // ClickSense summary
77	        if (clicksenseData.length > 0) {
78	            var durations = clicksenseData.map(function(e) { return e.duration_ms; });
79	            var meanDur = Math.round(durations.reduce(function(a, b) { return a + b; }, 0) / durations.length);
80	            html += '<h3 style="margin-top:30px">ClickSense</h3>';
81	            html += '<p>' + clicksenseData.length + ' clicks captured. Mean hold duration: <strong>' + meanDur + 'ms</strong></p>';
82	        }
83	
84	        html += '<p style="margin-top:20px; color:#666">Full trial + clicksense data in console.</p></div>';
85	
86	        document.body.innerHTML = html;
87	        console.log('jsPsych data:', JSON.stringify(jsPsych.data.get().values(), null, 2));
88	        console.log('ClickSense data:', JSON.stringify(clicksenseData, null, 2));
89	    }
90	});
91	
92	var timeline = [];
93	
94	// Welcome (keyboard — just a splash screen)
95	timeline.push({
96	    type: jsPsychHtmlKeyboardResponse,
97	    stimulus: '<p>Welcome to the Stroop experiment.</p><p>Press <strong>SPACE</strong> to begin.</p>',
98	    choices: [' ']
99	});
100	
101	// Instructions
102	timeline.push({
103	    type: jsPsychHtmlKeyboardResponse,
104	    stimulus: '<p>A colored word will appear on screen.</p>' +
105	        '<p>Click the button matching the <strong>ink color</strong>, not the word.</p>' +
106	        '<p>Respond as quickly and accurately as you can.</p>' +
107	        '<p>Press <strong>SPACE</strong> to start.</p>',
108	    choices: [' '],
109	    post_trial_gap: 1000
110	});
111	
112	// Stimuli
113	var trials = [
114	    { stimulus: '<p class="stroop-word" style="color:red">SHIP</p>',     data: { word: 'SHIP',    color: 'red',   stimulus_type: 'unrelated',   correct_response: 0 }},
115	    { stimulus: '<p class="stroop-word" style="color:green">MONKEY</p>', data: { word: 'MONKEY',  color: 'green', stimulus_type: 'unrelated',   correct_response: 1 }},
116	    { stimulus: '<p class="stroop-word" style="color:blue">ZAMBONI</p>', data: { word: 'ZAMBONI', color: 'blue',  stimulus_type: 'unrelated',   correct_response: 2 }},
117	    { stimulus: '<p class="stroop-word" style="color:red">RED</p>',      data: { word: 'RED',     color: 'red',   stimulus_type: 'congruent',   correct_response: 0 }},
118	    { stimulus: '<p class="stroop-word" style="color:green">GREEN</p>',  data: { word: 'GREEN',   color: 'green', stimulus_type: 'congruent',   correct_response: 1 }},
119	    { stimulus: '<p class="stroop-word" style="color:blue">BLUE</p>',    data: { word: 'BLUE',    color: 'blue',  stimulus_type: 'congruent',   correct_response: 2 }},
120	    { stimulus: '<p class="stroop-word" style="color:red">GREEN</p>',    data: { word: 'GREEN',   color: 'red',   stimulus_type: 'incongruent', correct_response: 0 }},
121	    { stimulus: '<p class="stroop-word" style="color:green">BLUE</p>',   data: { word: 'BLUE',    color: 'green', stimulus_type: 'incongruent', correct_response: 1 }},
122	    { stimulus: '<p class="stroop-word" style="color:blue">RED</p>',     data: { word: 'RED',     color: 'blue',  stimulus_type: 'incongruent', correct_response: 2 }}
123	];
124	
125	// Fixation cross (no response)
126	var fixation = {
127	    type: jsPsychHtmlKeyboardResponse,
128	    stimulus: '<p class="fixation">+</p>',
129	    choices: "NO_KEYS",
130	    trial_duration: 500
131	};
132	
133	// Stroop trial — button response
134	var word = {
135	    type: jsPsychHtmlButtonResponse,
136	    stimulus: jsPsych.timelineVariable('stimulus'),
137	    choices: ['Red', 'Green', 'Blue'],
138	    data: jsPsych.timelineVariable('data'),
139	    on_finish: function(data) {
140	        data.correct = (data.response === data.correct_response);
141	    }
142	};
143	
144	timeline.push({
145	    timeline: [fixation, word],
146	    timeline_variables: trials,
147	    randomize_order: true
148	});
149	
150	jsPsych.run(timeline);
151	
152	</script>
153	</html>
