// ClickSense per-condition breakdown
if (clicksenseData.length > 0) {
    html += '<h3 style="margin-top:30px">ClickSense — Motor Dynamics</h3>';

    function csForCondition(type) {
        return clicksenseData.filter(function(e) { return e.stimulus_type === type; });
    }
    function mean(arr) {
        if (!arr.length) return NaN;
        return arr.reduce(function(a, b) { return a + b; }, 0) / arr.length;
    }
    function fmt(v) { return isFinite(v) ? Math.round(v) : '—'; }
    function fmt2(v) { return isFinite(v) ? v.toFixed(2) : '—'; }

    // Hold duration table
    html += '<h4 style="margin:16px 0 8px">Hold Duration (mousedown → mouseup)</h4>';
    html += '<table style="border-collapse:collapse; width:100%; text-align:center">';
    html += '<tr><th style="border-bottom:2px solid #333; padding:6px">Condition</th>' +
            '<th style="border-bottom:2px solid #333; padding:6px">N</th>' +
            '<th style="border-bottom:2px solid #333; padding:6px">Mean (ms)</th>' +
            '<th style="border-bottom:2px solid #333; padding:6px">Min</th>' +
            '<th style="border-bottom:2px solid #333; padding:6px">Max</th></tr>';

    ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
        var events = csForCondition(type);
        var durs = events.map(function(e) { return e.duration_ms; });
        var label = type.charAt(0).toUpperCase() + type.slice(1);
        html += '<tr><td style="padding:6px; border-bottom:1px solid #ddd">' + label + '</td>' +
                '<td style="padding:6px; border-bottom:1px solid #ddd">' + durs.length + '</td>' +
                '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt(mean(durs)) + '</td>' +
                '<td style="padding:6px; border-bottom:1px solid #ddd">' + (durs.length ? Math.min.apply(null, durs) : '—') + '</td>' +
                '<td style="padding:6px; border-bottom:1px solid #ddd">' + (durs.length ? Math.max.apply(null, durs) : '—') + '</td></tr>';
    });
    html += '</table>';

    // Approach dynamics table (only if available)
    var hasApproach = clicksenseData.some(function(e) { return e.approach; });
    if (hasApproach) {
        html += '<h4 style="margin:16px 0 8px">Approach Trajectory</h4>';
        html += '<table style="border-collapse:collapse; width:100%; text-align:center; font-size:0.9em">';
        html += '<tr><th style="border-bottom:2px solid #333; padding:6px">Condition</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Mean Velocity</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Final Velocity</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Decel.</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Corrections</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Distance (px)</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Pause (ms)</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Linearity</th>' +
                '<th style="border-bottom:2px solid #333; padding:6px">Trajectory</th></tr>';

        ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
            var events = csForCondition(type).filter(function(e) { return e.approach; });
            if (!events.length) return;
            var label = type.charAt(0).toUpperCase() + type.slice(1);
            var a = events.map(function(e) { return e.approach; });

            var velMean = mean(a.map(function(x) { return x.approach_velocity_mean || 0; }));
            var velFinal = mean(a.map(function(x) { return x.approach_velocity_final || 0; }));
            var decel = mean(a.map(function(x) { return x.approach_deceleration || 0; }));
            var corrections = mean(a.map(function(x) { return x.approach_corrections || 0; }));
            var dist = mean(a.map(function(x) { return x.approach_distance || 0; }));
            var pause = mean(a.map(function(x) { return x.approach_pause_ms || 0; }));
            var linearity = mean(a.map(function(x) { return x.approach_linearity || 0; }));

            // Most common trajectory type
            var trajCounts = {};
            a.forEach(function(x) {
                var t = x.approach_trajectory_type || 'unknown';
                trajCounts[t] = (trajCounts[t] || 0) + 1;
            });
            var trajMode = Object.keys(trajCounts).sort(function(a, b) { return trajCounts[b] - trajCounts[a]; })[0];

            html += '<tr><td style="padding:6px; border-bottom:1px solid #ddd">' + label + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(velMean) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(velFinal) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(decel) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(corrections) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt(dist) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt(pause) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(linearity) + '</td>' +
                    '<td style="padding:6px; border-bottom:1px solid #ddd">' + trajMode + '</td></tr>';
        });
        html += '</table>';
    }
}

html += '<p style="margin-top:20px; color:#666">Full trial + clicksense data in console.</p></div>';

