// --- Trial generation with counterbalanced button position ---

var COLORS = ['Red', 'Green', 'Blue'];
var COLOR_HEX = { Red: '#d32f2f', Green: '#388e3c', Blue: '#1565c0' };
var REPS = 6; // 6 reps × 9 stimuli = 54 trials

// All 6 permutations of 3 buttons
var BUTTON_ORDERS = [
    ['Red','Green','Blue'], ['Red','Blue','Green'],
    ['Green','Red','Blue'], ['Green','Blue','Red'],
    ['Blue','Red','Green'], ['Blue','Green','Red']
];

// 9 base stimuli
var baseStimuli = [
    { word: 'SHIP',    color: 'red',   stimulus_type: 'unrelated'   },
    { word: 'MONKEY',  color: 'green', stimulus_type: 'unrelated'   },
    { word: 'ZAMBONI', color: 'blue',  stimulus_type: 'unrelated'   },
    { word: 'RED',     color: 'red',   stimulus_type: 'congruent'   },
    { word: 'GREEN',   color: 'green', stimulus_type: 'congruent'   },
    { word: 'BLUE',    color: 'blue',  stimulus_type: 'congruent'   },
    { word: 'GREEN',   color: 'red',   stimulus_type: 'incongruent' },
    { word: 'BLUE',    color: 'green', stimulus_type: 'incongruent' },
    { word: 'RED',     color: 'blue',  stimulus_type: 'incongruent' }
];

// Build full trial list: each stimulus × 6 reps, each rep gets a different button order
// This perfectly counterbalances button position across reps
var allTrials = [];
baseStimuli.forEach(function(stim) {
    // Shuffle the 6 orderings for this stimulus
    var orders = BUTTON_ORDERS.slice();
    for (var i = orders.length - 1; i > 0; i--) {
        var j = Math.floor(Math.random() * (i + 1));
        var tmp = orders[i]; orders[i] = orders[j]; orders[j] = tmp;
    }
    for (var r = 0; r < REPS; r++) {
        var btnOrder = orders[r % orders.length];
        var correctColor = stim.color.charAt(0).toUpperCase() + stim.color.slice(1); // 'red' → 'Red'
        var correctIndex = btnOrder.indexOf(correctColor);
        allTrials.push({
            stimulus: '<p class="stroop-word" style="color:' + stim.color + '">' + stim.word + '</p>',
            button_order: btnOrder,
            data: {
                word: stim.word,
                color: stim.color,
                stimulus_type: stim.stimulus_type,
                correct_response: correctIndex,
                button_order: btnOrder.join('-'),
                correct_position: correctIndex // 0=left, 1=center, 2=right
            }
        });
    }
});

// Shuffle all trials
for (var i = allTrials.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    var tmp = allTrials[i]; allTrials[i] = allTrials[j]; allTrials[j] = tmp;
}

// Fixation cross (no response)
var fixation = {
    type: jsPsychHtmlKeyboardResponse,
    stimulus: '<p class="fixation">+</p>',
    choices: "NO_KEYS",
    trial_duration: 500
};

// Stroop trial — button response with per-trial button order
var word = {
    type: jsPsychHtmlButtonResponse,
    stimulus: jsPsych.timelineVariable('stimulus'),
    choices: jsPsych.timelineVariable('button_order'),
    button_html: '<button class="jspsych-btn stroop-btn">%choice%</button>',
    data: jsPsych.timelineVariable('data'),
    on_load: function() {
        // Color each button to match its label
        var btns = document.querySelectorAll('.stroop-btn');
        btns.forEach(function(btn) {
            var label = btn.textContent.trim();
            btn.style.backgroundColor = COLOR_HEX[label] || '#666';
        });
    },
    on_start: function(trial) {
        currentTrialMeta = {
            stimulus_type: trial.data.stimulus_type,
            word: trial.data.word,
            color: trial.data.color,
            button_order: trial.data.button_order,
            correct_position: trial.data.correct_position
        };
    },
    on_finish: function(data) {
        data.correct = (data.response === data.correct_response);
        currentTrialMeta = null;
    }
};

timeline.push({
    timeline: [fixation, word],
    timeline_variables: allTrials
});

