1	<!doctype html>
2	<html>
3	<head>
4	    <title>Stroop Task — jsPsych 7 + ClickSense</title>
5	    <script src="https://unpkg.com/jspsych@7.3.4"></script>
6	    <script src="https://unpkg.com/@jspsych/plugin-html-keyboard-response@1.1.3"></script>
7	    <script src="https://unpkg.com/@jspsych/plugin-html-button-response@1.1.3"></script>
8	    <script src="static/js/clicksense.js"></script>
9	    <link href="https://unpkg.com/jspsych@7.3.4/css/jspsych.css" rel="stylesheet">
10	    <style>
11	        .fixation { font-size: 50px; }
12	        .stroop-word { font-size: 50px; font-weight: bold; }
13	
14	        .jspsych-btn.stroop-btn {
15	            color: white; font-weight: bold;
16	            font-size: 18px; padding: 12px 32px; border: none; border-radius: 6px;
17	            min-width: 80px; cursor: pointer;
18	        }
19	
20	        #jspsych-html-button-response-btngroup {
21	            margin-top: 30px;
22	            gap: 16px;
23	        }
24	    </style>
25	</head>
26	<body></body>
27	<script>
28	
29	// --- ClickSense setup ---
30	var clicksenseData = [];
31	var currentTrialMeta = null; // set before each trial, tagged onto capture
32	var cs = new ClickSenseLib.ClickSense({
33	    enableApproachDynamics: true,
34	    onCapture: function(event) {
35	        if (currentTrialMeta) {
36	            event.stimulus_type = currentTrialMeta.stimulus_type;
37	            event.word = currentTrialMeta.word;
38	            event.color = currentTrialMeta.color;
39	            event.button_order = currentTrialMeta.button_order;
40	            event.correct_position = currentTrialMeta.correct_position;
41	        }
42	        clicksenseData.push(event);
43	        console.log('ClickSense:', event.duration_ms + 'ms', event);
44	    }
45	});
46	
47	// --- jsPsych ---
48	var jsPsych = initJsPsych({
49	    on_finish: function() {
50	        var congruent = jsPsych.data.get().filter({stimulus_type: 'congruent'});
51	        var incongruent = jsPsych.data.get().filter({stimulus_type: 'incongruent'});
52	        var unrelated = jsPsych.data.get().filter({stimulus_type: 'unrelated'});
53	
54	        var html = '<div style="max-width:700px; margin:60px auto; font-family:sans-serif; line-height:1.6">';
55	        html += '<h2>Results</h2>';
56	
57	        // RT + accuracy table
58	        html += '<table style="border-collapse:collapse; width:100%; text-align:center">';
59	        html += '<tr><th style="border-bottom:2px solid #333; padding:8px">Condition</th>' +
60	                '<th style="border-bottom:2px solid #333; padding:8px">Mean RT (ms)</th>' +
61	                '<th style="border-bottom:2px solid #333; padding:8px">Accuracy</th></tr>';
62	
63	        [[congruent, 'Congruent'], [incongruent, 'Incongruent'], [unrelated, 'Unrelated']].forEach(function(pair) {
64	            var d = pair[0], label = pair[1];
65	            var rt = Math.round(d.select('rt').mean());
66	            var acc = Math.round(100 * d.select('correct').mean());
67	            html += '<tr><td style="padding:8px; border-bottom:1px solid #ddd">' + label + '</td>' +
68	                    '<td style="padding:8px; border-bottom:1px solid #ddd">' + rt + '</td>' +
69	                    '<td style="padding:8px; border-bottom:1px solid #ddd">' + acc + '%</td></tr>';
70	        });
71	        html += '</table>';
72	
73	        // ClickSense per-condition breakdown
74	        if (clicksenseData.length > 0) {
75	            html += '<h3 style="margin-top:30px">ClickSense — Motor Dynamics</h3>';
76	
77	            function csForCondition(type) {
78	                return clicksenseData.filter(function(e) { return e.stimulus_type === type; });
79	            }
80	            function mean(arr) {
81	                if (!arr.length) return NaN;
82	                return arr.reduce(function(a, b) { return a + b; }, 0) / arr.length;
83	            }
84	            function fmt(v) { return isFinite(v) ? Math.round(v) : '—'; }
85	            function fmt2(v) { return isFinite(v) ? v.toFixed(2) : '—'; }
86	
87	            // Hold duration table
88	            html += '<h4 style="margin:16px 0 8px">Hold Duration (mousedown → mouseup)</h4>';
89	            html += '<table style="border-collapse:collapse; width:100%; text-align:center">';
90	            html += '<tr><th style="border-bottom:2px solid #333; padding:6px">Condition</th>' +
91	                    '<th style="border-bottom:2px solid #333; padding:6px">N</th>' +
92	                    '<th style="border-bottom:2px solid #333; padding:6px">Mean (ms)</th>' +
93	                    '<th style="border-bottom:2px solid #333; padding:6px">Min</th>' +
94	                    '<th style="border-bottom:2px solid #333; padding:6px">Max</th></tr>';
95	
96	            ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
97	                var events = csForCondition(type);
98	                var durs = events.map(function(e) { return e.duration_ms; });
99	                var label = type.charAt(0).toUpperCase() + type.slice(1);
100	                html += '<tr><td style="padding:6px; border-bottom:1px solid #ddd">' + label + '</td>' +
101	                        '<td style="padding:6px; border-bottom:1px solid #ddd">' + durs.length + '</td>' +
