184	    choices: [' '],
185	    post_trial_gap: 1000
186	});
187	
188	// --- Trial generation with counterbalanced button position ---
189	
190	var COLORS = ['Red', 'Green', 'Blue'];
191	var COLOR_HEX = { Red: '#d32f2f', Green: '#388e3c', Blue: '#1565c0' };
192	var REPS = 6; // 6 reps × 9 stimuli = 54 trials
193	
194	// All 6 permutations of 3 buttons
195	var BUTTON_ORDERS = [
196	    ['Red','Green','Blue'], ['Red','Blue','Green'],
197	    ['Green','Red','Blue'], ['Green','Blue','Red'],
198	    ['Blue','Red','Green'], ['Blue','Green','Red']
199	];
200	
201	// 9 base stimuli
202	var baseStimuli = [
203	    { word: 'SHIP',    color: 'red',   stimulus_type: 'unrelated'   },
204	    { word: 'MONKEY',  color: 'green', stimulus_type: 'unrelated'   },
205	    { word: 'ZAMBONI', color: 'blue',  stimulus_type: 'unrelated'   },
206	    { word: 'RED',     color: 'red',   stimulus_type: 'congruent'   },
207	    { word: 'GREEN',   color: 'green', stimulus_type: 'congruent'   },
208	    { word: 'BLUE',    color: 'blue',  stimulus_type: 'congruent'   },
209	    { word: 'GREEN',   color: 'red',   stimulus_type: 'incongruent' },
210	    { word: 'BLUE',    color: 'green', stimulus_type: 'incongruent' },
211	    { word: 'RED',     color: 'blue',  stimulus_type: 'incongruent' }
212	];
213	
214	// Build full trial list: each stimulus × 6 reps, each rep gets a different button order
215	// This perfectly counterbalances button position across reps
216	var allTrials = [];
217	baseStimuli.forEach(function(stim) {
218	    // Shuffle the 6 orderings for this stimulus
219	    var orders = BUTTON_ORDERS.slice();
220	    for (var i = orders.length - 1; i > 0; i--) {
221	        var j = Math.floor(Math.random() * (i + 1));
222	        var tmp = orders[i]; orders[i] = orders[j]; orders[j] = tmp;
223	    }
224	    for (var r = 0; r < REPS; r++) {
225	        var btnOrder = orders[r % orders.length];
226	        var correctColor = stim.color.charAt(0).toUpperCase() + stim.color.slice(1); // 'red' → 'Red'
227	        var correctIndex = btnOrder.indexOf(correctColor);
228	        allTrials.push({
229	            stimulus: '<p class="stroop-word" style="color:' + stim.color + '">' + stim.word + '</p>',
230	            button_order: btnOrder,
231	            data: {
232	                word: stim.word,
233	                color: stim.color,
234	                stimulus_type: stim.stimulus_type,
235	                correct_response: correctIndex,
236	                button_order: btnOrder.join('-'),
237	                correct_position: correctIndex // 0=left, 1=center, 2=right
238	            }
239	        });
240	    }
241	});
242	
243	// Shuffle all trials
244	for (var i = allTrials.length - 1; i > 0; i--) {
245	    var j = Math.floor(Math.random() * (i + 1));
246	    var tmp = allTrials[i]; allTrials[i] = allTrials[j]; allTrials[j] = tmp;
247	}
248	
249	// Fixation cross (no response)
250	var fixation = {
251	    type: jsPsychHtmlKeyboardResponse,
252	    stimulus: '<p class="fixation">+</p>',
253	    choices: "NO_KEYS",
254	    trial_duration: 500
255	};
256	
257	// Stroop trial — button response with per-trial button order
258	var word = {
259	    type: jsPsychHtmlButtonResponse,
260	    stimulus: jsPsych.timelineVariable('stimulus'),
261	    choices: jsPsych.timelineVariable('button_order'),
262	    button_html: '<button class="jspsych-btn stroop-btn">%choice%</button>',
263	    data: jsPsych.timelineVariable('data'),
264	    on_load: function() {
265	        // Color each button to match its label
266	        var btns = document.querySelectorAll('.stroop-btn');
267	        btns.forEach(function(btn) {
268	            var label = btn.textContent.trim();
269	            btn.style.backgroundColor = COLOR_HEX[label] || '#666';
270	        });
271	    },
272	    on_start: function(trial) {
273	        currentTrialMeta = {
274	            stimulus_type: trial.data.stimulus_type,
275	            word: trial.data.word,
276	            color: trial.data.color,
277	            button_order: trial.data.button_order,
278	            correct_position: trial.data.correct_position
279	        };
280	    },
281	    on_finish: function(data) {
282	        data.correct = (data.response === data.correct_response);
283	        currentTrialMeta = null;
284	    }
285	};
286	
287	timeline.push({
288	    timeline: [fixation, word],
289	    timeline_variables: allTrials
290	});
291	
292	jsPsych.run(timeline);
293	
294	</script>
295	</html>
