        if (currentTrialMeta) {
            event.stimulus_type = currentTrialMeta.stimulus_type;
            event.word = currentTrialMeta.word;
            event.color = currentTrialMeta.color;
            event.button_order = currentTrialMeta.button_order;
            event.correct_position = currentTrialMeta.correct_position;
        }
        clicksenseData.push(event);

        // Send to PostHog with trial-level properties
        var phEvent = Object.assign({}, event);
        if (currentTrialMeta) {
            phEvent.stimulus_type = currentTrialMeta.stimulus_type;
            phEvent.word = currentTrialMeta.word;
            phEvent.color = currentTrialMeta.color;
            phEvent.button_order = currentTrialMeta.button_order;
            phEvent.correct_position = currentTrialMeta.correct_position;
        }
        posthogAdapter(phEvent);

        console.log('ClickSense:', event.duration_ms + 'ms', event);
    }
});

