// Send summary event to PostHog
if (window.posthog) {
    var summary = { experiment: 'stroop', session_id: sessionId, total_trials: 54 };
    ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
        var d = jsPsych.data.get().filter({stimulus_type: type});
        summary[type + '_rt_mean'] = Math.round(d.select('rt').mean());
