        var cs = clicksenseData.filter(function(e) { return e.stimulus_type === type; });
        if (cs.length) {
            var durs = cs.map(function(e) { return e.duration_ms; });
            summary[type + '_hold_mean'] = Math.round(durs.reduce(function(a,b){return a+b;},0) / durs.length);
        }
    });
    // Stroop effect (incongruent - congruent)
    summary.stroop_effect_rt = summary.incongruent_rt_mean - summary.congruent_rt_mean;
    if (summary.incongruent_hold_mean && summary.congruent_hold_mean) {
        summary.stroop_effect_hold = summary.incongruent_hold_mean - summary.congruent_hold_mean;
    }
    posthog.capture('stroop_complete', summary);
}

