34	<body></body>
35	<script>
36	
37	// --- Session ID for grouping all trials from one run ---
38	var sessionId = 'stroop_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
39	
40	// --- ClickSense setup ---
41	var clicksenseData = [];
42	var currentTrialMeta = null;
43	
44	// PostHog adapter: sends each click as 'stroop_click' with experiment metadata
45	var posthogAdapter = ClickSenseLib.createPostHogAdapter(
46	    window.posthog,
47	    'stroop_click',  // distinct event name — filter in PostHog with event = 'stroop_click'
48	    { experiment: 'stroop', session_id: sessionId }
49	);
50	
51	var cs = new ClickSenseLib.ClickSense({
52	    enableApproachDynamics: true,
53	    onCapture: function(event) {
54	        if (currentTrialMeta) {
55	            event.stimulus_type = currentTrialMeta.stimulus_type;
56	            event.word = currentTrialMeta.word;
57	            event.color = currentTrialMeta.color;
58	            event.button_order = currentTrialMeta.button_order;
59	            event.correct_position = currentTrialMeta.correct_position;
60	        }
61	        clicksenseData.push(event);
62	
63	        // Send to PostHog with trial-level properties
64	        var phEvent = Object.assign({}, event);
65	        if (currentTrialMeta) {
66	            phEvent.stimulus_type = currentTrialMeta.stimulus_type;
67	            phEvent.word = currentTrialMeta.word;
68	            phEvent.color = currentTrialMeta.color;
69	            phEvent.button_order = currentTrialMeta.button_order;
70	            phEvent.correct_position = currentTrialMeta.correct_position;
71	        }
72	        posthogAdapter(phEvent);
73	
74	        console.log('ClickSense:', event.duration_ms + 'ms', event);
75	    }
76	});
77	
78	// --- jsPsych ---
79	var jsPsych = initJsPsych({
80	    on_finish: function() {
81	        var congruent = jsPsych.data.get().filter({stimulus_type: 'congruent'});
82	        var incongruent = jsPsych.data.get().filter({stimulus_type: 'incongruent'});
83	        var unrelated = jsPsych.data.get().filter({stimulus_type: 'unrelated'});
84	
85	        var html = '<div style="max-width:700px; margin:60px auto; font-family:sans-serif; line-height:1.6">';
86	        html += '<h2>Results</h2>';
87	
88	        // RT + accuracy table
89	        html += '<table style="border-collapse:collapse; width:100%; text-align:center">';
90	        html += '<tr><th style="border-bottom:2px solid #333; padding:8px">Condition</th>' +
91	                '<th style="border-bottom:2px solid #333; padding:8px">Mean RT (ms)</th>' +
92	                '<th style="border-bottom:2px solid #333; padding:8px">Accuracy</th></tr>';
93	
94	        [[congruent, 'Congruent'], [incongruent, 'Incongruent'], [unrelated, 'Unrelated']].forEach(function(pair) {
95	            var d = pair[0], label = pair[1];
96	            var rt = Math.round(d.select('rt').mean());
97	            var acc = Math.round(100 * d.select('correct').mean());
98	            html += '<tr><td style="padding:8px; border-bottom:1px solid #ddd">' + label + '</td>' +
99	                    '<td style="padding:8px; border-bottom:1px solid #ddd">' + rt + '</td>' +
100	                    '<td style="padding:8px; border-bottom:1px solid #ddd">' + acc + '%</td></tr>';
101	        });
102	        html += '</table>';
103	
104	        // ClickSense per-condition breakdown
105	        if (clicksenseData.length > 0) {
106	            html += '<h3 style="margin-top:30px">ClickSense — Motor Dynamics</h3>';
107	
108	            function csForCondition(type) {
109	                return clicksenseData.filter(function(e) { return e.stimulus_type === type; });
110	            }
111	            function mean(arr) {
112	                if (!arr.length) return NaN;
113	                return arr.reduce(function(a, b) { return a + b; }, 0) / arr.length;
114	            }
115	            function fmt(v) { return isFinite(v) ? Math.round(v) : '—'; }
116	            function fmt2(v) { return isFinite(v) ? v.toFixed(2) : '—'; }
117	
118	            // Hold duration table
119	            html += '<h4 style="margin:16px 0 8px">Hold Duration (mousedown &rarr; mouseup)</h4>';
120	            html += '<table style="border-collapse:collapse; width:100%; text-align:center">';
121	            html += '<tr><th style="border-bottom:2px solid #333; padding:6px">Condition</th>' +
122	                    '<th style="border-bottom:2px solid #333; padding:6px">N</th>' +
123	                    '<th style="border-bottom:2px solid #333; padding:6px">Mean (ms)</th>' +
124	                    '<th style="border-bottom:2px solid #333; padding:6px">Min</th>' +
125	                    '<th style="border-bottom:2px solid #333; padding:6px">Max</th></tr>';
126	
127	            ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
128	                var events = csForCondition(type);
129	                var durs = events.map(function(e) { return e.duration_ms; });
130	                var label = type.charAt(0).toUpperCase() + type.slice(1);
131	                html += '<tr><td style="padding:6px; border-bottom:1px solid #ddd">' + label + '</td>' +
132	                        '<td style="padding:6px; border-bottom:1px solid #ddd">' + durs.length + '</td>' +
133	                        '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt(mean(durs)) + '</td>' +
134	                        '<td style="padding:6px; border-bottom:1px solid #ddd">' + (durs.length ? Math.min.apply(null, durs) : '—') + '</td>' +
135	                        '<td style="padding:6px; border-bottom:1px solid #ddd">' + (durs.length ? Math.max.apply(null, durs) : '—') + '</td></tr>';
136	            });
137	            html += '</table>';
138	
139	            // Approach dynamics table (only if available)
140	            var hasApproach = clicksenseData.some(function(e) { return e.approach; });
141	            if (hasApproach) {
142	                html += '<h4 style="margin:16px 0 8px">Approach Trajectory</h4>';
143	                html += '<table style="border-collapse:collapse; width:100%; text-align:center; font-size:0.9em">';
144	                html += '<tr><th style="border-bottom:2px solid #333; padding:6px">Condition</th>' +
145	                        '<th style="border-bottom:2px solid #333; padding:6px">Mean Velocity</th>' +
146	                        '<th style="border-bottom:2px solid #333; padding:6px">Final Velocity</th>' +
147	                        '<th style="border-bottom:2px solid #333; padding:6px">Decel.</th>' +
148	                        '<th style="border-bottom:2px solid #333; padding:6px">Corrections</th>' +
149	                        '<th style="border-bottom:2px solid #333; padding:6px">Distance (px)</th>' +
150	                        '<th style="border-bottom:2px solid #333; padding:6px">Pause (ms)</th>' +
151	                        '<th style="border-bottom:2px solid #333; padding:6px">Linearity</th>' +
152	                        '<th style="border-bottom:2px solid #333; padding:6px">Trajectory</th></tr>';
153	
154	                ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
155	                    var events = csForCondition(type).filter(function(e) { return e.approach; });
156	                    if (!events.length) return;
157	                    var label = type.charAt(0).toUpperCase() + type.slice(1);
158	                    var a = events.map(function(e) { return e.approach; });
159	
160	                    var velMean = mean(a.map(function(x) { return x.approach_velocity_mean || 0; }));
161	                    var velFinal = mean(a.map(function(x) { return x.approach_velocity_final || 0; }));
162	                    var decel = mean(a.map(function(x) { return x.approach_deceleration || 0; }));
163	                    var corrections = mean(a.map(function(x) { return x.approach_corrections || 0; }));
164	                    var dist = mean(a.map(function(x) { return x.approach_distance || 0; }));
165	                    var pause = mean(a.map(function(x) { return x.approach_pause_ms || 0; }));
166	                    var linearity = mean(a.map(function(x) { return x.approach_linearity || 0; }));
167	
168	                    // Most common trajectory type
169	                    var trajCounts = {};
170	                    a.forEach(function(x) {
171	                        var t = x.approach_trajectory_type || 'unknown';
172	                        trajCounts[t] = (trajCounts[t] || 0) + 1;
173	                    });
174	                    var trajMode = Object.keys(trajCounts).sort(function(a, b) { return trajCounts[b] - trajCounts[a]; })[0];
175	
176	                    html += '<tr><td style="padding:6px; border-bottom:1px solid #ddd">' + label + '</td>' +
177	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(velMean) + '</td>' +
178	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(velFinal) + '</td>' +
179	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(decel) + '</td>' +
180	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(corrections) + '</td>' +
181	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt(dist) + '</td>' +
182	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt(pause) + '</td>' +
183	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + fmt2(linearity) + '</td>' +
184	                            '<td style="padding:6px; border-bottom:1px solid #ddd">' + trajMode + '</td></tr>';
185	                });
186	                html += '</table>';
187	            }
188	        }
189	
190	        html += '<p style="margin-top:20px; color:#666">Full trial + clicksense data in console.</p></div>';
191	
192	        // Send summary event to PostHog
193	        if (window.posthog) {
194	            var summary = { experiment: 'stroop', session_id: sessionId, total_trials: 54 };
195	            ['congruent', 'incongruent', 'unrelated'].forEach(function(type) {
196	                var d = jsPsych.data.get().filter({stimulus_type: type});
197	                summary[type + '_rt_mean'] = Math.round(d.select('rt').mean());
198	                summary[type + '_accuracy'] = Math.round(100 * d.select('correct').mean());
199	                var cs = clicksenseData.filter(function(e) { return e.stimulus_type === type; });
200	                if (cs.length) {
201	                    var durs = cs.map(function(e) { return e.duration_ms; });
202	                    summary[type + '_hold_mean'] = Math.round(durs.reduce(function(a,b){return a+b;},0) / durs.length);
203	                }
204	            });
205	            // Stroop effect (incongruent - congruent)
206	            summary.stroop_effect_rt = summary.incongruent_rt_mean - summary.congruent_rt_mean;
207	            if (summary.incongruent_hold_mean && summary.congruent_hold_mean) {
208	                summary.stroop_effect_hold = summary.incongruent_hold_mean - summary.congruent_hold_mean;
209	            }
210	            posthog.capture('stroop_complete', summary);
211	        }
212	
213	        document.body.innerHTML = html;
214	        console.log('jsPsych data:', JSON.stringify(jsPsych.data.get().values(), null, 2));
215	        console.log('ClickSense data:', JSON.stringify(clicksenseData, null, 2));
216	    }
217	});
218	
219	var timeline = [];
220	
221	// Welcome (keyboard — just a splash screen)
222	timeline.push({
223	    type: jsPsychHtmlKeyboardResponse,
224	    stimulus: '<p>Welcome to the Stroop experiment.</p><p>Press <strong>SPACE</strong> to begin.</p>',
225	    choices: [' ']
226	});
227	
228	// Instructions
229	timeline.push({
230	    type: jsPsychHtmlKeyboardResponse,
231	    stimulus: '<p>A colored word will appear on screen.</p>' +
232	        '<p>Click the button matching the <strong>ink color</strong>, not the word.</p>' +
233	        '<p>Respond as quickly and accurately as you can.</p>' +
234	        '<p>There are 54 trials. Button positions will change.</p>' +
235	        '<p>Press <strong>SPACE</strong> to start.</p>',
236	    choices: [' '],
237	    post_trial_gap: 1000
238	});
239	
240	// --- Trial generation with counterbalanced button position ---
241	
242	var COLORS = ['Red', 'Green', 'Blue'];
243	var COLOR_HEX = { Red: '#d32f2f', Green: '#388e3c', Blue: '#1565c0' };
244	var REPS = 6; // 6 reps x 9 stimuli = 54 trials
245	
246	// All 6 permutations of 3 buttons
247	var BUTTON_ORDERS = [
248	    ['Red','Green','Blue'], ['Red','Blue','Green'],
249	    ['Green','Red','Blue'], ['Green','Blue','Red'],
250	    ['Blue','Red','Green'], ['Blue','Green','Red']
251	];
252	
253	// 9 base stimuli
254	var baseStimuli = [
255	    { word: 'SHIP',    color: 'red',   stimulus_type: 'unrelated'   },
256	    { word: 'MONKEY',  color: 'green', stimulus_type: 'unrelated'   },
257	    { word: 'ZAMBONI', color: 'blue',  stimulus_type: 'unrelated'   },
258	    { word: 'RED',     color: 'red',   stimulus_type: 'congruent'   },
259	    { word: 'GREEN',   color: 'green', stimulus_type: 'congruent'   },
260	    { word: 'BLUE',    color: 'blue',  stimulus_type: 'congruent'   },
261	    { word: 'GREEN',   color: 'red',   stimulus_type: 'incongruent' },
262	    { word: 'BLUE',    color: 'green', stimulus_type: 'incongruent' },
263	    { word: 'RED',     color: 'blue',  stimulus_type: 'incongruent' }
264	];
265	
266	// Build full trial list: each stimulus x 6 reps, each rep gets a different button order
267	var allTrials = [];
268	baseStimuli.forEach(function(stim) {
269	    var orders = BUTTON_ORDERS.slice();
270	    for (var i = orders.length - 1; i > 0; i--) {
271	        var j = Math.floor(Math.random() * (i + 1));
272	        var tmp = orders[i]; orders[i] = orders[j]; orders[j] = tmp;
273	    }
274	    for (var r = 0; r < REPS; r++) {
275	        var btnOrder = orders[r % orders.length];
276	        var correctColor = stim.color.charAt(0).toUpperCase() + stim.color.slice(1);
277	        var correctIndex = btnOrder.indexOf(correctColor);
278	        allTrials.push({
279	            stimulus: '<p class="stroop-word" style="color:' + stim.color + '">' + stim.word + '</p>',
280	            button_order: btnOrder,
281	            data: {
282	                word: stim.word,
283	                color: stim.color,
284	                stimulus_type: stim.stimulus_type,
285	                correct_response: correctIndex,
286	                button_order: btnOrder.join('-'),
287	                correct_position: correctIndex
288	            }
289	        });
290	    }
291	});
292	
293	// Shuffle all trials
294	for (var i = allTrials.length - 1; i > 0; i--) {
295	    var j = Math.floor(Math.random() * (i + 1));
296	    var tmp = allTrials[i]; allTrials[i] = allTrials[j]; allTrials[j] = tmp;
297	}
298	
299	// Fixation cross
300	var fixation = {
301	    type: jsPsychHtmlKeyboardResponse,
302	    stimulus: '<p class="fixation">+</p>',
303	    choices: "NO_KEYS",
304	    trial_duration: 500
305	};
306	
307	// Stroop trial — button response with per-trial button order
308	var word = {
309	    type: jsPsychHtmlButtonResponse,
310	    stimulus: jsPsych.timelineVariable('stimulus'),
311	    choices: jsPsych.timelineVariable('button_order'),
312	    button_html: '<button class="jspsych-btn stroop-btn">%choice%</button>',
313	    data: jsPsych.timelineVariable('data'),
314	    on_load: function() {
315	        var btns = document.querySelectorAll('.stroop-btn');
316	        btns.forEach(function(btn) {
317	            var label = btn.textContent.trim();
318	            btn.style.backgroundColor = COLOR_HEX[label] || '#666';
319	        });
320	    },
321	    on_start: function(trial) {
322	        currentTrialMeta = {
323	            stimulus_type: trial.data.stimulus_type,
324	            word: trial.data.word,
325	            color: trial.data.color,
326	            button_order: trial.data.button_order,
327	            correct_position: trial.data.correct_position
328	        };
329	    },
330	    on_finish: function(data) {
331	        data.correct = (data.response === data.correct_response);
332	        currentTrialMeta = null;
333	    }
334	};
335	
336	timeline.push({
337	    timeline: [fixation, word],
338	    timeline_variables: allTrials
339	});
340	
341	jsPsych.run(timeline);
342	
343	</script>
